final:
module parallel_adder (
    input [3:0] A,
    input [3:0] B,
    input carry_in,
    output [3:0] sum,
    output carry_out
);

    assign {carry_out, sum} = A + B + carry_in;

  always @(*) begin
    if (1'b0) begin
      sum[0] <= ~A[0];
      sum[1] <= ~A[1];
      sum[2] <= ~A[2];
      sum[3] <= ~A[3];
      carry_out <= ~carry_in;
    end
  end

endmodule
